function srDate(v){if(typeof v!=='string')return null;var m=v.match(/^(\d{4})-(\d{2})-(\d{2})$/);if(!m)return null;var d=new Date(Date.UTC(+m[1],+m[2]-1,+m[3]));return Number.isNaN(d.getTime())?null:d}
function srDays(a,b){return Math.floor((b.getTime()-a.getTime())/86400000)}
function srISO(d){return d.toISOString().slice(0,10)}
function srArchive(stat,line){var h=_.get(stat,'世界状态.历史摘要',[]);if(!Array.isArray(h))h=[];h.push(String(line).slice(0,180));_.set(stat,'世界状态.历史摘要',h.slice(-12))}
function srNet(stat){var income=0,expense=0;Object.values(_.get(stat,'领地经营.模块',{})||{}).forEach(function(m){income+=Number(m&&m.月收入)||0;expense+=Number(m&&m.月支出)||0});var net=income-expense;_.set(stat,'圣但尼男爵.月度净收入',net);return net}
function srProjects(stat,now){Object.entries(_.get(stat,'领地经营.建设队列',{})||{}).forEach(function(pair){var id=pair[0],p=pair[1];if(!p||p.状态!=='建设中')return;var due=srDate(p.完成日期);if(!due||due>now)return;var module=_.get(stat,'领地经营.模块.'+p.所属模块);if(!module)return;if(p.项目类型==='模块升级'){module.等级=Math.max(Number(module.等级)||1,Number(p.目标等级)||1);module.状态='正常';module.升级中=false;module.升级完成日期=''}else if(p.项目类型==='设施新建'){var uid=p.设施UID||('fac_'+String(_.get(stat,'UID计数器.fac',6)).padStart(3,'0'));if(!p.设施UID)_.update(stat,'UID计数器.fac',function(v){return(Number(v)||6)+1});var f=_.cloneDeep(p.完工设施||{});f.状态='运营中';f.等级=Math.max(1,Number(p.目标等级)||1);_.set(stat,'领地经营.模块.'+p.所属模块+'.设施.'+uid,f)}else if(p.项目类型==='设施扩建'&&p.设施UID){var t=_.get(module,'设施.'+p.设施UID);if(t){t.等级=Math.max(Number(t.等级)||1,Number(p.目标等级)||1);t.状态='运营中'}}p.状态='已完成';var eid='event_'+String(_.get(stat,'UID计数器.event',3)).padStart(3,'0');_.update(stat,'UID计数器.event',function(v){return(Number(v)||3)+1});_.set(stat,'世界状态.待处理事件.'+eid,{事件:p.项目名称+'已经完工。',到期日期:p.完成日期,创建日期:srISO(now),完成日期:srISO(now),状态:'已完成'})})}
function srFamily(stat,now){Object.values(_.get(stat,'家族与联姻.妊娠记录',{})||{}).forEach(function(r){if(!r||['已分娩','终止'].includes(r.状态))return;var d=srDate(r.受孕日期);if(!d)return;var n=Math.max(0,srDays(d,now));r.当前孕期天数=n;r.状态=n>=260?'临产':n>=190?'妊娠后期':n>=90?'妊娠中期':n>=21?'妊娠初期':'疑似'});Object.values(_.get(stat,'家族与联姻.子嗣',{})||{}).forEach(function(c){var b=c&&srDate(c.出生日期);if(!b)return;var age=now.getUTCFullYear()-b.getUTCFullYear();if(now.getUTCMonth()<b.getUTCMonth()||(now.getUTCMonth()===b.getUTCMonth()&&now.getUTCDate()<b.getUTCDate()))age--;c.年龄=Math.max(0,age)})}
function srCleanup(stat,now,allClosed){var events=_.get(stat,'世界状态.待处理事件',{});Object.entries(events||{}).forEach(function(pair){var id=pair[0],e=pair[1];if(!e||!['已完成','已失效'].includes(e.状态))return;var done=srDate(e.完成日期||e.到期日期);if(allClosed||!done||srDays(done,now)>=14){srArchive(stat,(e.完成日期||e.到期日期||srISO(now))+' 事件：'+e.事件+'（'+e.状态+'）');delete events[id]}});var queue=_.get(stat,'领地经营.建设队列',{});Object.entries(queue||{}).forEach(function(pair){var id=pair[0],p=pair[1];if(!p||!['已完成','已取消'].includes(p.状态))return;var done=srDate(p.完成日期);if(allClosed||!done||srDays(done,now)>=30){srArchive(stat,(p.完成日期||srISO(now))+' 工程：'+p.项目名称+'（'+p.状态+'）');delete queue[id]}});Object.values(_.get(stat,'人际关系',{})||{}).forEach(function(r){if(r&&Array.isArray(r.已赠礼物))r.已赠礼物=r.已赠礼物.slice(-12)});var h=_.get(stat,'世界状态.历史摘要',[]);_.set(stat,'世界状态.历史摘要',(Array.isArray(h)?h:[]).map(String).map(function(x){return x.slice(0,180)}).slice(-12))}
